static scd4x_runtime_fault_cause_t scd4x_runtime_classify_fault(
    const scd41_context_t* context, int16_t error) {
    uint32_t hal_error = 0U;

    if (context != NULL) {
        hal_error = context->i2c_hal_error;
    }

    if (error == NO_ERROR) {
        return SCD4X_RUNTIME_FAULT_NONE;
    }

    /* NOT_IMPLEMENTED_ERROR (31) = loi RTOS noi bo (mutex/heap), KHONG phai loi I2C. */
    if (error == (int16_t)NOT_IMPLEMENTED_ERROR) {
        return SCD4X_RUNTIME_FAULT_RTOS;
    }

    if ((error == (int16_t)HAL_TIMEOUT) || ((hal_error & HAL_I2C_ERROR_TIMEOUT) != 0U)) {
        return SCD4X_RUNTIME_FAULT_TIMEOUT;
    }

    if ((error == (int16_t)HAL_BUSY)) {
        return SCD4X_RUNTIME_FAULT_BUSY;
    }

    if ((hal_error & HAL_I2C_ERROR_AF) != 0U) {
        return SCD4X_RUNTIME_FAULT_NO_ACK;
    }

    if ((hal_error & (HAL_I2C_ERROR_BERR | HAL_I2C_ERROR_ARLO | HAL_I2C_ERROR_OVR)) != 0U) {
        return SCD4X_RUNTIME_FAULT_BUS;
    }

    if (error == CRC_ERROR) {
        return SCD4X_RUNTIME_FAULT_CRC;
    }

    if (error == (int16_t)HAL_ERROR) {
        return SCD4X_RUNTIME_FAULT_NO_ACK;
    }

    return SCD4X_RUNTIME_FAULT_UNKNOWN;
}

