void scd4x_runtime_default_itm_event_handler(const scd41_config_t* config,
                                             const scd41_context_t* context,
                                             scd4x_runtime_event_t event,
                                             void* user_context) {
    bool same_fault;

    (void)user_context;

    if (context == NULL) {
        return;
    }

    switch (event) {
        case SCD4X_RUNTIME_EVENT_FAULT:
            same_fault = g_scd4x_itm_fault_log_state.has_active_fault &&
                         (g_scd4x_itm_fault_log_state.context == context) &&
                         (g_scd4x_itm_fault_log_state.cause == context->fault_cause) &&
                         (g_scd4x_itm_fault_log_state.error == context->error) &&
                         (g_scd4x_itm_fault_log_state.hal_state == context->i2c_hal_state) &&
                         (g_scd4x_itm_fault_log_state.hal_error == context->i2c_hal_error);

            if (same_fault) {
                g_scd4x_itm_fault_log_state.repeat_count++;
            } else {
                g_scd4x_itm_fault_log_state.context = context;
                g_scd4x_itm_fault_log_state.cause = context->fault_cause;
                g_scd4x_itm_fault_log_state.error = context->error;
                g_scd4x_itm_fault_log_state.hal_state = context->i2c_hal_state;
                g_scd4x_itm_fault_log_state.hal_error = context->i2c_hal_error;
                g_scd4x_itm_fault_log_state.repeat_count = 1U;
                g_scd4x_itm_fault_log_state.has_active_fault = true;
            }

            if (g_scd4x_itm_short_log_enabled && same_fault) {
                break;
            }

            if (g_scd4x_itm_short_log_enabled) {
                itm_print("[SCD41][ERR] ");
                itm_print(scd4x_runtime_bus_to_text(config));
                itm_print(": ");
                itm_print(scd4x_runtime_fault_simple_text(context->fault_cause));
                itm_print(".\r\n");
                break;
            }

            itm_print("[SCD41][FAULT] cause=");
            itm_print(scd4x_runtime_fault_cause_to_text(context->fault_cause));
            itm_print("(");
            itm_put_int((int)context->fault_cause);
            itm_print(")");
            itm_print(", err=");
            itm_print(scd4x_runtime_error_to_text(context->error));
            itm_print("(");
            itm_put_int((int)context->error);
            itm_print(")");
            itm_print(", state=");
            itm_print(scd4x_runtime_i2c_state_to_text(context->i2c_hal_state));
            itm_print("(");
            itm_put_int((int)context->i2c_hal_state);
            itm_print(")");
            itm_print(", hal_error=");
            scd4x_runtime_print_i2c_error_flags(context->i2c_hal_error);
            itm_print("(");
            itm_put_int((int)context->i2c_hal_error);
            itm_print(")");
            itm_print(", hint=");
            itm_print(scd4x_runtime_fault_hint(context->fault_cause));
            itm_print(", count=");
            itm_put_int((int)g_scd4x_itm_fault_log_state.repeat_count);
            itm_print("\r\n");
            break;

        case SCD4X_RUNTIME_EVENT_RECOVERED: {
            uint32_t n = g_scd4x_itm_fault_log_state.repeat_count;
            scd4x_runtime_fault_cause_t prev_cause = g_scd4x_itm_fault_log_state.cause;
            g_scd4x_itm_fault_log_state.has_active_fault = false;
            g_scd4x_itm_fault_log_state.repeat_count = 0U;
            itm_print("[SCD41] ");
            itm_print(scd4x_runtime_bus_to_text(config));
            itm_print(": da ket noi lai sensor");
            if (n > 1U) {
                itm_print(" (sau ");
                itm_put_int((int)n);
                itm_print(" lan loi ");
                itm_print(scd4x_runtime_fault_cause_to_text(prev_cause));
                itm_print(")");
            }
            itm_print("\r\n");
            break;
        }

        case SCD4X_RUNTIME_EVENT_RESTART_ATTEMPT:
            if (!g_scd4x_itm_short_log_enabled) {
                itm_print("[SCD41] retry start periodic measurement\r\n");
            }
            break;

        default:
            break;
    }
}

