void scd4x_init(uint8_t i2c_address) {
    _i2c_address = i2c_address;
}

void scd4x_runtime_init(scd41_config_t* config,
                        scd41_context_t* context) {
    if ((config == NULL) || (context == NULL)) {
        return;
    }

    if (config->i2c_address == 0U) {
        config->i2c_address = SCD41_I2C_ADDR_62;
    }
    if (config->restart_after_failures == 0U) {
        config->restart_after_failures = 5U;
    }

    context->co2 = 0;
    context->temperature_m_deg_c = 0;
    context->humidity_m_percent_rh = 0;
    context->data_ready = false;
    context->error = NO_ERROR;
    context->i2c_hal_state = 0U;
    context->i2c_hal_error = 0U;
    context->consecutive_error_count = 0U;
    context->total_error_count = 0U;
    context->fault_active = false;
    context->fault_cause = SCD4X_RUNTIME_FAULT_NONE;
    context->on_event = NULL;
    context->on_event_context = NULL;
    scd4x_runtime_fault_flag_sync(context);

    sensirion_i2c_hal_set_handle(config->i2c_handle);
    sensirion_i2c_hal_set_mutex(config->i2c_mutex);
    scd4x_init(config->i2c_address);
    scd4x_runtime_update_diag(config, context);
}

int16_t scd4x_runtime_start_periodic_measurement(const scd41_config_t* config,
                                                 scd41_context_t* context) {
    if ((config == NULL) || (context == NULL) || (config->i2c_handle == NULL) ||
        (config->i2c_mutex == NULL)) {
        return NOT_IMPLEMENTED_ERROR;
    }

    context->error = scd4x_runtime_lock(config);
    if (context->error != NO_ERROR) {
        return context->error;
    }

    sensirion_i2c_hal_set_handle(config->i2c_handle);
    sensirion_i2c_hal_set_mutex(config->i2c_mutex);
    scd4x_init(config->i2c_address);

    context->error = scd4x_start_periodic_measurement();
    scd4x_runtime_unlock(config);

    scd4x_runtime_update_diag(config, context);
    if (context->error == NO_ERROR) {
        /* Chỉ in START khi không đang trong trạng thái lỗi (init bình thường).
         * Khi đang fault (retry hoặc recovery), nơi gọi sẽ tự in nếu cần. */
        if (!context->fault_active) {
            itm_print("[SCD41] START_PERIODIC_MEASUREMENT\r\n");
        }
        context->consecutive_error_count = 0U;
    }

    return context->error;
}

int16_t scd4x_runtime_read_if_ready(const scd41_config_t* config,
                                    scd41_context_t* context) {
    if ((config == NULL) || (context == NULL) || (config->i2c_handle == NULL) ||
        (config->i2c_mutex == NULL)) {
        return NOT_IMPLEMENTED_ERROR;
    }

    context->error = scd4x_runtime_lock(config);
    if (context->error != NO_ERROR) {
        return context->error;
    }

    sensirion_i2c_hal_set_handle(config->i2c_handle);
    sensirion_i2c_hal_set_mutex(config->i2c_mutex);
    scd4x_init(config->i2c_address);

    context->error = scd4x_get_data_ready_status(&context->data_ready);
    if (context->error != NO_ERROR) {
        scd4x_runtime_unlock(config);
        scd4x_runtime_update_diag(config, context);
        return context->error;
    }

    if (!context->data_ready) {
        scd4x_runtime_unlock(config);
        scd4x_runtime_update_diag(config, context);
        return NO_ERROR;
    }

    context->error = scd4x_read_measurement(&context->co2,
                                            &context->temperature_m_deg_c,
                                            &context->humidity_m_percent_rh);
    scd4x_runtime_unlock(config);
    scd4x_runtime_update_diag(config, context);
    return context->error;
}

bool scd4x_runtime_poll(const scd41_config_t* config, scd41_context_t* context) {
    int16_t restart_error;
    bool fault_was_active;

    if ((config == NULL) || (context == NULL)) {
        return false;
    }

    fault_was_active = context->fault_active;
//    scd4x_runtime_fault_cause_t fault_cause_snapshot = context->fault_cause;
    context->error = scd4x_runtime_read_if_ready(config, context);
    if (context->error == NO_ERROR) {
        /* After any fault (including CRC), force start command once bus is alive again
         * and sensor is not yet producing data (data_ready=false).
         * If the sensor was actually still running (transient CRC), it will NACK the START
         * command, causing one extra fault cycle then recovering normally — acceptable.
         * If we do NOT restart after CRC disconnect, the sensor stays idle forever. */
        if (fault_was_active && !context->data_ready) {
            _measurement_running = false;
            (void)scd4x_runtime_start_periodic_measurement(config, context);
            /* Print START chỉ khi lệnh thật sự thành công (sensor đã sống lại). */
            if (context->error == NO_ERROR) {
                itm_print("[SCD41] START_PERIODIC_MEASUREMENT\r\n");
            }
            context->error = scd4x_runtime_read_if_ready(config, context);
        }

        if (context->error != NO_ERROR) {
            context->total_error_count++;
            context->consecutive_error_count++;
            context->fault_cause = scd4x_runtime_classify_fault(context, context->error);
            context->fault_active = true;
            scd4x_runtime_notify(config, context, SCD4X_RUNTIME_EVENT_FAULT);
            return false;
        }

        context->consecutive_error_count = 0U;
        context->fault_cause = SCD4X_RUNTIME_FAULT_NONE;

        if (context->fault_active) {
            context->fault_active = false;
            scd4x_runtime_notify(config, context, SCD4X_RUNTIME_EVENT_RECOVERED);
        }

        return context->data_ready;
    }

    context->total_error_count++;
    context->consecutive_error_count++;
    context->fault_cause = scd4x_runtime_classify_fault(context, context->error);

    if (context->fault_cause != SCD4X_RUNTIME_FAULT_CRC) {
        _measurement_running = false;
    }

    if (!context->fault_active) {
        context->fault_active = true;
        scd4x_runtime_notify(config, context, SCD4X_RUNTIME_EVENT_FAULT);
    } else {
        /* Notify again on each fault to allow caller-specific policies. */
        scd4x_runtime_notify(config, context, SCD4X_RUNTIME_EVENT_FAULT);
    }

    if ((config->restart_after_failures > 0U) &&
        ((context->consecutive_error_count % config->restart_after_failures) == 0U)) {
        scd4x_runtime_notify(config, context, SCD4X_RUNTIME_EVENT_RESTART_ATTEMPT);
        restart_error = scd4x_runtime_start_periodic_measurement(config, context);
        if (restart_error == NO_ERROR) {
            context->consecutive_error_count = 0U;
        }
    }

    return false;
}

bool Scd41Api_Service(const scd41_config_t* config,
                      scd41_context_t* context,
                      osMessageQueueId_t queue,
                      scd4x_runtime_event_callback_t on_event) {
    scd41_queue_item_t item;

    if ((queue == NULL) || (config == NULL) || (context == NULL)) {
        return false;
    }

    /* Set callback once on first run, or when caller changes callback/context. */
    if ((context->on_event != on_event) ||
        (context->on_event_context != (void*)context)) {
        scd4x_runtime_set_event_callback(config, context, on_event, (void*)context);
    }

    if (!scd4x_runtime_poll(config, context)) {
        scd4x_runtime_fault_flag_sync(context);
        return false;
    }

    scd4x_runtime_fault_flag_sync(context);

    item.co2 = context->co2;
    item.temperature_m_deg_c = context->temperature_m_deg_c;
    item.humidity_m_percent_rh = context->humidity_m_percent_rh;

    return (osMessageQueuePut(queue, &item, 0U, 0U) == osOK);
}

